"""Search engine - full-text search over indexed documents.

Provides indexing and querying capabilities for text documents
with support for basic relevance scoring.
"""
from typing import Optional


class SearchEngine:
    """Engine for full-text document search."""

    name = "search"

    def __init__(self, config: dict = None):
        self.config = config or {}
        self._index = {}
        self._documents = {}
        self._doc_count = 0

    def initialize(self) -> None:
        """Initialize the search index."""
        self._index.clear()
        self._documents.clear()
        self._doc_count = 0

    def index_document(self, doc_id: str, content: str, metadata: dict = None) -> None:
        """Add a document to the search index."""
        self._documents[doc_id] = {
            "content": content,
            "metadata": metadata or {},
        }
        words = content.lower().split()
        for word in set(words):
            if word not in self._index:
                self._index[word] = []
            self._index[word].append(doc_id)
        self._doc_count += 1

    def search(self, query: str, limit: int = 10) -> list[dict]:
        """Search for documents matching the query."""
        query_words = query.lower().split()
        scores = {}
        for word in query_words:
            for doc_id in self._index.get(word, []):
                scores[doc_id] = scores.get(doc_id, 0) + 1
        ranked = sorted(scores.items(), key=lambda x: x[1], reverse=True)
        results = []
        for doc_id, score in ranked[:limit]:
            doc = self._documents[doc_id]
            results.append({
                "doc_id": doc_id,
                "score": score,
                "content": doc["content"][:200],
                "metadata": doc["metadata"],
            })
        return results

    def get_stats(self) -> dict:
        """Return index statistics."""
        return {
            "document_count": self._doc_count,
            "term_count": len(self._index),
        }

    def process(self, data: dict) -> dict:
        """Process a search request."""
        query = data.get("query", "")
        limit = data.get("limit", 10)
        results = self.search(query, limit)
        return {"results": results, "count": len(results)}

    def shutdown(self) -> None:
        """Cleanup search engine resources."""
        self._index.clear()
        self._documents.clear()

