"""Export engine - data export to various formats.

Supports exporting processed data to CSV, JSON, and XML formats
with configurable output options.
"""
import json
import csv
import io
from typing import Optional


class ExportEngine:
    """Engine for exporting data to various file formats."""

    name = "export"

    def __init__(self, config: dict = None):
        self.config = config or {}
        self._format = config.get("format", "json") if config else "json"
        self._export_count = 0

    def initialize(self) -> None:
        """Initialize export engine."""
        self._export_count = 0

    def export_json(self, data: list[dict], pretty: bool = True) -> str:
        """Export data as JSON string."""
        indent = 2 if pretty else None
        self._export_count += 1
        return json.dumps(data, indent=indent)

    def export_csv(self, data: list[dict]) -> str:
        """Export data as CSV string."""
        if not data:
            return ""
        output = io.StringIO()
        writer = csv.DictWriter(output, fieldnames=data[0].keys())
        writer.writeheader()
        writer.writerows(data)
        self._export_count += 1
        return output.getvalue()

    def process(self, data: dict) -> dict:
        """Process an export request."""
        fmt = data.get("format", self._format)
        records = data.get("records", [])
        if fmt == "json":
            output = self.export_json(records)
        elif fmt == "csv":
            output = self.export_csv(records)
        else:
            return {"error": f"Unsupported format: {fmt}"}
        return {"output": output, "format": fmt, "record_count": len(records)}

    def get_stats(self) -> dict:
        """Return export statistics."""
        return {
            "exports_completed": self._export_count,
            "default_format": self._format,
        }

    def shutdown(self) -> None:
        """Cleanup export engine resources."""
        pass

