"""Main application module.

Orchestrates engine creation, data routing, and pipeline execution.
"""
import json
import logging
from typing import Optional
from registry import create_engine, list_engines, REGISTRY
from types import EngineType, validate_engine

logger = logging.getLogger(__name__)


class Application:
    """Main application that manages engine lifecycle."""

    def __init__(self, config: dict = None):
        self.config = config or {}
        self._engines = {}
        self._initialized = False

    def setup(self, engine_names: list[str] = None) -> None:
        """Initialize requested engines.

        If no engine names specified, initializes all registered engines
        including search, analytics, and export.
        """
        if engine_names is None:
            engine_names = list_engines()

        for name in engine_names:
            engine_config = self.config.get(name, {})
            engine = create_engine(name, engine_config)
            if validate_engine(engine):
                self._engines[name] = engine
                logger.info(f"Initialized engine: {name}")
            else:
                logger.warning(f"Engine {name} does not implement protocol")

        self._initialized = True

    def process(self, engine_name: str, data: dict) -> dict:
        """Route data to a specific engine for processing."""
        if not self._initialized:
            raise RuntimeError("Application not initialized. Call setup() first.")
        if engine_name not in self._engines:
            available = ", ".join(self._engines.keys())
            raise ValueError(f"Engine '{engine_name}' not available. Active: {available}")
        return self._engines[engine_name].process(data)

    def run_pipeline(self, steps: list[dict]) -> list[dict]:
        """Run a multi-step processing pipeline.

        Each step is a dict with 'engine' and 'data' keys.
        The analytics engine can be included to track pipeline metrics.
        """
        results = []
        for step in steps:
            engine_name = step["engine"]
            data = step.get("data", {})
            result = self.process(engine_name, data)
            results.append(result)
        return results

    def get_engine(self, name: str) -> Optional[EngineType]:
        """Get a specific engine instance by name."""
        return self._engines.get(name)

    def shutdown(self) -> None:
        """Shutdown all engines gracefully."""
        for name, engine in self._engines.items():
            engine.shutdown()
            logger.info(f"Shutdown engine: {name}")
        self._engines.clear()
        self._initialized = False
